  assignments: readonly AssignmentWithReceiptUser[];
};

/**
 * Receipt with related line items and user from Zero query
 */
export type ReceiptWithLineItems = UserReceipt & {
  line_items: readonly LineItemWithAssignments[];
  user?: User | null;
};

/**
