 * Rebalance: changing `targetId` to `newValue`. Returns the next shares map.
 */
function rebalance(
  entries: DraftEntry[],
  targetId: string,
  newValue: number
): DraftEntry[] {
  const target = entries.find((e) => e.assignmentId === targetId);
  if (!target || target.locked) return entries;

  const lockedSum = entries
    .filter((e) => e.locked)
    .reduce((s, e) => s + e.share, 0);

  let clamped = Math.max(0, Math.min(100, newValue));
  if (clamped + lockedSum > 100) clamped = 100 - lockedSum;

  const others = entries.filter(
    (e) => e.assignmentId !== targetId && !e.locked
  );
  const remaining = 100 - clamped - lockedSum;
  const othersSum = others.reduce((s, e) => s + e.share, 0);

  return entries.map((e) => {
    if (e.assignmentId === targetId) return { ...e, share: clamped };
    if (e.locked) return e;
    const next =
      othersSum > 0
        ? (e.share / othersSum) * remaining
        : remaining / Math.max(others.length, 1);
    return { ...e, share: next };
  });
}

const SplitPercentTab: React.FC<SplitPercentTabProps> = ({
  item,
  chipColors,
  formPricePerItem,
  formQuantity,
}) => {
  const { t } = useLingui();
  const zero = useZero();

  const seedKey = useMemo(
    () =>
      item.assignments
        .map(
          (a) =>
            `${a.id}:${a.sharePercentage?.toString() ?? 'null'}:${a.locked ? 1 : 0}`
        )
        .join('|'),
    [item.assignments]
  );

  const seedEntries = useMemo<DraftEntry[]>(() => {
    const n = item.assignments.length;
    const evenShare = n > 0 ? 100 / n : 0;
    return item.assignments.map((a) => ({
      assignmentId: a.id,
      receiptUserId: a.receiptUserId,
      displayName: getUserDisplayName(a),
      share: a.sharePercentage != null ? a.sharePercentage.toNumber() : evenShare,
      locked: a.locked,
    }));
  }, [item.assignments]);

  const [entries, setEntries] = useState<DraftEntry[]>(seedEntries);

  // Re-seed when the underlying assignments change (add/remove or remote update).
  // eslint-disable-next-line react-hooks/exhaustive-deps
  useEffect(() => setEntries(seedEntries), [seedKey]);

  const persistTimers = useRef<Map<string, ReturnType<typeof setTimeout>>>(
    new Map()
  );

  const persistShare = (assignmentId: string, share: number) => {
    const existing = persistTimers.current.get(assignmentId);
    if (existing) clearTimeout(existing);
    const timer = setTimeout(() => {
      void zero.mutate(
        mutators.assignments.update({
          id: assignmentId,
          share_percentage: share,
        })
      );
      persistTimers.current.delete(assignmentId);
    }, 150);
    persistTimers.current.set(assignmentId, timer);
  };

  const persistAllShares = (next: DraftEntry[], previous: DraftEntry[]) => {
    for (const e of next) {
      const prev = previous.find((p) => p.assignmentId === e.assignmentId);
      if (!prev || prev.share !== e.share) {
        persistShare(e.assignmentId, e.share);
      }
    }
  };

  const handleChange = (assignmentId: string, value: number) => {
    setEntries((prev) => {
      const next = rebalance(prev, assignmentId, value);
      persistAllShares(next, prev);
      return next;
    });
  };

  const handleToggleLock = (assignmentId: string) => {
    setEntries((prev) => {
      const next = prev.map((e) =>
        e.assignmentId === assignmentId ? { ...e, locked: !e.locked } : e
      );
      const target = next.find((e) => e.assignmentId === assignmentId);
      if (target) {
        void zero.mutate(
          mutators.assignments.update({
            id: assignmentId,
            locked: target.locked,
          })
        );
      }
      return next;
    });
  };

  const handleReset = () => {
    setEntries((prev) => {
      const n = prev.length;
      const evenShare = n > 0 ? 100 / n : 0;
      const next = prev.map((e) => ({ ...e, share: evenShare, locked: false }));
      for (const e of next) {
        void zero.mutate(mutators.assignments.update({
          id: e.assignmentId,
          share_percentage: evenShare,
          locked: false,
        });
      }
      return next;
    });
  };

  const itemTotal = calculations.pretax.getIndividualItemTotalPrice(item, {
    pricePerItem: formPricePerItem,
    quantity: formQuantity,
  });

  const roundedPercents = useMemo(
    () => largestRemainderRound(entries.map((e) => e.share)),
    [entries]
  );

  if (item.assignments.length < 2) {
    return (
      <div className="rounded-md p-4 text-center text-sm text-muted-foreground">
        <Trans>Assign 2+ people to customize the split.</Trans>
      </div>
    );
  }

  return (
    <div className="flex flex-col gap-6 p-2">
      <ul className="flex flex-col gap-5">
        {entries.map((entry, idx) => {
          const c = chipColors.get(entry.receiptUserId) ?? DEFAULT_CHIP_COLOR;
          const dollar = itemTotal.mul(entry.share).div(100);
          const percentDisplay = roundedPercents[idx] ?? 0;
          return (
            <li key={entry.assignmentId} className="flex flex-col gap-2">
              <div className="flex items-center gap-3">
                <Avatar className={cn('ring-1', c.ring)} title={entry.displayName}>
                  <AvatarFallback className={cn(c.bg, c.text)}>
                    {getInitials(entry.displayName)}
                  </AvatarFallback>
                </Avatar>
                <span className="flex-1 truncate">{entry.displayName}</span>
                <div
                  className={cn(
                    'flex items-center gap-1 rounded-full bg-muted px-3 py-1',
                    entry.locked && 'opacity-60'
                  )}
                >
                  <input
                    type="number"
                    min={0}
                    max={100}
                    value={percentDisplay}
                    disabled={entry.locked}
                    onChange={(e) => {
                      const v = Number(e.target.value);
                      if (Number.isFinite(v)) handleChange(entry.assignmentId, v);
                    }}
                    className="w-10 bg-transparent text-right text-base outline-none md:text-sm"
                    aria-label={t`${entry.displayName} percent`}
                  />
                  <span className="text-sm text-muted-foreground">%</span>
                </div>
                <span className="w-16 text-right tabular-nums">
                  {formatCurrency(dollar)}
                </span>
              </div>
              <div className="flex items-center gap-3">
                <Slider
                  value={[entry.share]}
                  min={0}
                  max={100}
                  step={1}
                  disabled={entry.locked}
                  onValueChange={(vals) =>
                    handleChange(entry.assignmentId, vals[0] ?? 0)
                  }
                  className="flex-1"
                  aria-label={t`${entry.displayName} share slider`}
                />
                <Button
                  type="button"
                  variant={entry.locked ? 'default' : 'secondary'}
                  size="icon"
                  className="size-11 shrink-0"
                  onClick={() => handleToggleLock(entry.assignmentId)}
                  aria-label={
                    entry.locked
                      ? t`Unlock ${entry.displayName}`
                      : t`Lock ${entry.displayName}`
                  }
                  title={
                    entry.locked
                      ? t`Unlock ${entry.displayName}`
                      : t`Lock ${entry.displayName}`
                  }
                >
                  {entry.locked ? <Lock /> : <Unlock />}
                </Button>
              </div>
            </li>
          );
        })}
      </ul>
      <div className="flex justify-center">
        <Button
          type="button"
          variant="link"
          size="sm"
          onClick={handleReset}
        >
          <Trans>Reset to even split</Trans>
        </Button>
      </div>
    </div>
  );
};

export default SplitPercentTab;

