/**
 * Largest-remainder rounding: returns integer percents that sum to 100.
 */
function largestRemainderRound(values: number[]): number[] {
  const floors = values.map((v) => Math.floor(v));
  const remainders = values.map((v, i) => ({ i, frac: v - floors[i] }));
  let deficit = 100 - floors.reduce((a, b) => a + b, 0);
  remainders.sort((a, b) => b.frac - a.frac);
  const result = [...floors];
  for (let k = 0; k < remainders.length && deficit > 0; k++) {
    result[remainders[k].i] += 1;
