import type { Assignment } from '@/models/Assignment';
import { mutators } from '@/zero/mutators';

type SiblingShareUpdate = { id: string; share_percentage: number };
type AddRebalanceResult = {
  newcomerShare: number;
  newcomerLocked: boolean;
  siblingUpdates: SiblingShareUpdate[];
  warning: 'fully-locked' | null;
};

const itemHasCustomShares = (assignments: readonly Assignment[]) =>
  assignments.some((a) => a.sharePercentage != null);

function planAddRebalance(
  activeSiblings: readonly Assignment[]
): AddRebalanceResult | null {
  if (!itemHasCustomShares(activeSiblings)) return null;

  const siblings = activeSiblings.map((a) => ({
    id: a.id,
    share: a.sharePercentage?.toNumber() ?? 0,
    locked: a.locked,
  }));
  const lockedSum = siblings
    .filter((s) => s.locked)
    .reduce((acc, s) => acc + s.share, 0);
  const unlocked = siblings.filter((s) => !s.locked);
  const unlockedSum = unlocked.reduce((acc, s) => acc + s.share, 0);
  const headroom = Math.max(0, 100 - lockedSum);

  if (headroom <= 0 || unlocked.length === 0) {
    return {
      newcomerShare: 0,
      newcomerLocked: false,
      siblingUpdates: [],
      warning: 'fully-locked',
    };
  }

  const fair = 100 / (siblings.length + 1);
  const newcomerShare = Math.min(fair, headroom);
  const remainingForUnlocked = headroom - newcomerShare;

  const siblingUpdates: SiblingShareUpdate[] = unlocked.map((s) => ({
    id: s.id,
    share_percentage:
      unlockedSum > 0
        ? (s.share / unlockedSum) * remainingForUnlocked
        : remainingForUnlocked / unlocked.length,
  }));

  return {
    newcomerShare,
    newcomerLocked: false,
    siblingUpdates,
    warning: null,
  };
}

function planRemoveRebalance(
  removed: Assignment,
  remainingActive: readonly Assignment[]
): SiblingShareUpdate[] | null {
  if (removed.sharePercentage == null) return null;
  if (remainingActive.length === 0) return null;

  const removedShare = removed.sharePercentage.toNumber();
  const siblings = remainingActive.map((a) => ({
    id: a.id,
    share: a.sharePercentage?.toNumber() ?? 100 / remainingActive.length,
    locked: a.locked,
  }));
  const unlocked = siblings.filter((s) => !s.locked);
  const unlockedSum = unlocked.reduce((acc, s) => acc + s.share, 0);

  if (unlocked.length === 0) {
    // All remaining are locked: spread evenly across everyone (clears locks via fresh shares).
    const even = 100 / siblings.length;
    return siblings.map((s) => ({ id: s.id, share_percentage: even }));
  }

  return unlocked.map((s) => ({
    id: s.id,
    share_percentage:
      unlockedSum > 0
        ? s.share + (s.share / unlockedSum) * removedShare
        : s.share + removedShare / unlocked.length,
  }));
}

