41	  const floors = values.map((v) => Math.floor(v));
42	  const remainders = values.map((v, i) => ({ i, frac: v - floors[i] }));
43	  let deficit = 100 - floors.reduce((a, b) => a + b, 0);
44	  remainders.sort((a, b) => b.frac - a.frac);
45	  const result = [...floors];
46	  for (let k = 0; k < remainders.length && deficit > 0; k++) {
47	    result[remainders[k].i] += 1;
48	    deficit -= 1;
49	  }
